namespace BgControls.Windows.Controls.DragDrop;/// <summary>/// 拖放操作配置选项类./// </summary>public class DragDropOptions{    /// <summary>    /// 拖拽源元素的弱引用.    /// </summary>    private WeakReference? sourceReference;    /// <summary>    /// 参与操作的视觉根节点集合.    /// </summary>    private IList<UIElement>? participatingVisualRoots;    /// <summary>    /// Initializes a new instance of the <see cref="DragDropOptions"/> class.    /// </summary>    public DragDropOptions()    {        // 构造函数初始化逻辑.    }    /// <summary>    /// Gets or sets 负载数据.    /// </summary>    public object? Payload { get; set; }    /// <summary>    /// Gets or sets 放置的数据对象.    /// </summary>    public DataObject? DropDataObject { get; set; }    /// <summary>    /// Gets or sets 拖放效果.    /// </summary>    public DragDropEffects? Effects { get; set; }    /// <summary>    /// Gets or sets 当前光标.    /// </summary>    public Cursor? CurrentCursor { get; set; }    /// <summary>    /// Gets 拖拽源元素.    /// </summary>    public FrameworkElement? Source    {        get        {            // 检查弱引用对象是否存在且目标依然存活.            if (this.sourceReference != null && this.sourceReference.IsAlive)            {                return this.sourceReference.Target as FrameworkElement;            }            return null;        }        internal set        {            // 为传入的源元素创建新的弱引用.            this.sourceReference = new WeakReference(value);        }    }    /// <summary>    /// Gets or sets 拖拽目标元素.    /// </summary>    public FrameworkElement? Destination { get; set; }    /// <summary>    /// Gets or sets 箭头提示控件.    /// </summary>    public ContentControl? ArrowCue { get; set; }    /// <summary>    /// Gets or sets 拖拽提示内容.    /// </summary>    public object? DragCue { get; set; }    /// <summary>    /// Gets 鼠标点击位置.    /// </summary>    public Point MouseClickPoint { get; internal set; }    /// <summary>    /// Gets 当前拖拽位置.    /// </summary>    public Point CurrentDragPoint { get; internal set; }    /// <summary>    /// Gets 相对拖拽位置.    /// </summary>    public Point RelativeDragPoint { get; internal set; }    /// <summary>    /// Gets 拖拽状态.    /// </summary>    public DragStatus Status { get; internal set; }    /// <summary>    /// Gets 参与的视觉根节点集合.    /// </summary>    public IList<UIElement> ParticipatingVisualRoots    {        get        {            // 如果集合为空则进行延迟初始化.            if (this.participatingVisualRoots == null)            {                this.participatingVisualRoots = new List<UIElement>();            }            return this.participatingVisualRoots;        }    }    /// <summary>    /// Gets or sets 拖拽提示显示行为.    /// </summary>    public VisualCueBehavior DragCueDisplayBehavior { get; set; }    /// <summary>    /// Gets or sets 箭头提示显示行为.    /// </summary>    public VisualCueBehavior ArrowCueDisplayBehavior { get; set; }}